   438→// removeSecretReference updates the given ServiceAccount to remove a reference to the given secretName if needed.
   439→func (e *TokensController) removeSecretReference(saNamespace string, saName string, saUID types.UID, secretName string) error {
   440→	// We don't want to update the cache's copy of the service account
   441→	// so remove the secret from a freshly retrieved copy of the service account
   442→	serviceAccounts := e.client.CoreV1().ServiceAccounts(saNamespace)
   443→	serviceAccount, err := serviceAccounts.Get(context.TODO(), saName, metav1.GetOptions{})
   444→	// Ignore NotFound errors when attempting to remove a reference
   445→	if apierrors.IsNotFound(err) {
   446→		return nil
   447→	}
   448→	if err != nil {
   449→		return err
   450→	}
   451→
   452→	// Short-circuit if the UID doesn't match
   453→	if len(saUID) > 0 && saUID != serviceAccount.UID {
   454→		return nil
   455→	}
   456→
   457→	// Short-circuit if the secret is no longer referenced
   458→	if !getSecretReferences(serviceAccount).Has(secretName) {
   459→		return nil
   460→	}
   461→
   462→	// Remove the secret
   463→	secrets := []v1.ObjectReference{}
   464→	for _, s := range serviceAccount.Secrets {
   465→		if s.Name != secretName {
   466→			secrets = append(secrets, s)
   467→		}
   468→	}
   469→	serviceAccount.Secrets = secrets
   470→	_, err = serviceAccounts.Update(context.TODO(), serviceAccount, metav1.UpdateOptions{})
   471→	// Ignore NotFound errors when attempting to remove a reference
   472→	if apierrors.IsNotFound(err) {
   473→		return nil
   474→	}
   475→	return err
   476→}
