   478→func (e *TokensController) getServiceAccount(ns string, name string, uid types.UID, fetchOnCacheMiss bool) (*v1.ServiceAccount, error) {
   479→	// Look up in cache
   480→	sa, err := e.serviceAccounts.ServiceAccounts(ns).Get(name)
   481→	if err != nil && !apierrors.IsNotFound(err) {
   482→		return nil, err
   483→	}
   484→	if sa != nil {
   485→		// Ensure UID matches if given
   486→		if len(uid) == 0 || uid == sa.UID {
   487→			return sa, nil
   488→		}
   489→	}
   490→
   491→	if !fetchOnCacheMiss {
   492→		return nil, nil
   493→	}
   494→
   495→	// Live lookup
   496→	sa, err = e.client.CoreV1().ServiceAccounts(ns).Get(context.TODO(), name, metav1.GetOptions{})
   497→	if apierrors.IsNotFound(err) {
   498→		return nil, nil
   499→	}
   500→	if err != nil {
   501→		return nil, err
   502→	}
   503→	// Ensure UID matches if given
   504→	if len(uid) == 0 || uid == sa.UID {
   505→		return sa, nil
   506→	}
   507→	return nil, nil
   508→}
