   546→// listTokenSecrets returns a list of all of the ServiceAccountToken secrets that
   547→// reference the given service account's name and uid
   548→func (e *TokensController) listTokenSecrets(serviceAccount *v1.ServiceAccount) ([]*v1.Secret, error) {
   549→	namespaceSecrets, err := e.updatedSecrets.ByIndex("namespace", serviceAccount.Namespace)
   550→	if err != nil {
   551→		return nil, err
   552→	}
   553→
   554→	items := []*v1.Secret{}
   555→	for _, obj := range namespaceSecrets {
   556→		secret := obj.(*v1.Secret)
   557→
   558→		if apiserverserviceaccount.IsServiceAccountToken(secret, serviceAccount) {
   559→			items = append(items, secret)
   560→		}
   561→	}
   562→	return items, nil
   563→}
