   127→func (s *Plugin) ValidateInitialization() error {
   128→	if s.client == nil {
   129→		return fmt.Errorf("missing client")
   130→	}
   131→	if s.serviceAccountLister == nil {
   132→		return fmt.Errorf("missing serviceAccountLister")
