   273→
   274→	if value, ok := serviceAccount.Annotations[EnforceMountableSecretsAnnotation]; ok {
   275→		enforceMountableSecretCheck, _ := strconv.ParseBool(value)
   276→		return enforceMountableSecretCheck
   277→	}
   278→
   279→	return false
